const question = $('Extract Question & User').first().json.question;
const asked_by = $('Extract Question & User').first().json.asked_by;
const docs = items;

// Only use relevant chunks above score threshold
const relevantDocs = docs.filter(doc => doc.json.score > 0.3);

let context = '';
const sources = [];

relevantDocs.forEach((doc, index) => {
  const text = doc.json.document?.pageContent || '';
  const docName = doc.json.document?.metadata?.doc_name || 'Unknown';

  if (text) {
    context += `\n[Source ${index + 1}: ${docName}]\n${text}\n`;
    if (!sources.includes(docName)) sources.push(docName);
  }
});

// If no relevant context found
if (context.trim() === '') {
  context = 'No relevant documents found in the knowledge base.';
}

const prompt = `You are an internal company knowledge assistant. Answer the employee's question using ONLY the context provided below. 

If the answer is not found in the context, say exactly: "I don't have that information in the knowledge base. Please check with the relevant team."

Never make up information. Always cite which document your answer comes from.

CONTEXT:
${context}

QUESTION: ${question}

Respond in this JSON format:
{
  "answer": "string",
  "sources": ["doc name 1", "doc name 2"],
  "confidence": "high | medium | low",
  "found_in_kb": true or false
}`;

return [{
  json: {
    prompt,
    question,
    asked_by,
    sources: sources.join(', ')
  }
}];

const response = items[0].json.output[0].content[0].text;
const cleaned = response.replace(/```json|```/g, '').trim();
const parsed = JSON.parse(cleaned);

const question = $('Extract Question & User').first().json.question;
const asked_by = $('Extract Question & User').first().json.asked_by;

return [{
  json: {
    question,
    asked_by,
    answer: parsed.answer,
    sources: parsed.sources.join(', '),
    confidence: parsed.confidence,
    found_in_kb: parsed.found_in_kb,
    timestamp: new Date().toISOString()
  }
}];

const driveDocs = $('List Knowledge Base Docs1').all();
const registry = $('Read Document Registry').all();

// Build registry lookup by doc_id
const registryMap = {};
registry.forEach(r => {
  registryMap[r.json.doc_id] = r.json;
});

const newDocs = [];
const existingDocs = [];
const allDocs = [];

driveDocs.forEach(doc => {
  const docId = doc.json.id;
  const docName = doc.json.name;
  const modifiedTime = doc.json.modifiedTime || '';

  const inRegistry = registryMap[docId];

  if (!inRegistry) {
    // Brand new document never ingested
    newDocs.push({ docId, docName, status: 'new' });
  } else {
    // Check if modified after last ingestion
    const lastIngested = new Date(inRegistry.last_ingested);
    const lastModified = new Date(modifiedTime);
    if (lastModified > lastIngested) {
      newDocs.push({ docId, docName, status: 'updated' });
    } else {
      existingDocs.push({ docId, docName, status: 'current' });
    }
  }

  allDocs.push({
    docId,
    docName,
    status: registryMap[docId] ? 'current' : 'new'
  });
});

return [{
  json: {
    new_or_updated: newDocs,
    existing: existingDocs,
    all_docs: allDocs,
    total_docs: driveDocs.length,
    new_count: newDocs.length,
    existing_count: existingDocs.length,
    needs_ingestion: newDocs.length > 0
  }
}];

const newDocs = items[0].json.new_or_updated;

